func main() {
    nums := []int{1, 2, 3}
    fmt.Println(nums)          // [1 2 3]
    fmt.Println(len(nums))     // 3

    nums = append(nums, 4, 5)
    fmt.Println(nums)          // [1 2 3 4 5]

    zeros := make([]int, 5)    // [0 0 0 0 0]
    fmt.Println(zeros)
}

