func main() {
    nums := []int{10, 20, 30}

    // Index and value
    for i, v := range nums {
        fmt.Println(i, v)
    }

    // Value only
    for _, v := range nums {
        fmt.Println(v)
    }

    // C-style
    for i := 0; i < len(nums); i++ {
        fmt.Println(nums[i])
    }
}

