func main() {
    nums := []int{1, 2, 3, 4, 5}

    sub := nums[1:4]       // [2 3 4]
    fmt.Println(sub)

    // Copy to avoid aliasing
    clone := make([]int, len(nums))
    copy(clone, nums)

    // Remove element at index 2
    nums = append(nums[:2], nums[3:]...)
    fmt.Println(nums)      // [1 2 4 5]
}

